using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // ---------------------------------------------------------------
            // BREAKING CHANGE 1 — Discriminator property renamed
            // EF Core 9 writes "$type" instead of "Discriminator".
            // Existing 500K documents contain { "Discriminator": "Product" }
            // and raw SQL queries reference c.Discriminator.
            // Fix: keep the old property name and value.
            // ---------------------------------------------------------------
            b.HasDiscriminator<string>("Discriminator")
             .HasValue<Product>("Product");

            // ---------------------------------------------------------------
            // BREAKING CHANGE 2 — Cosmos document `id` format changed
            // EF Core 8 synthesised id as  "Product|123"  (Discriminator|PK).
            // EF Core 9 synthesises id as  "123"           (PK only).
            // Existing documents still carry the old format; a mismatch means
            // Find / point-reads return null and queries may miss rows.
            // Fix: override id generation to preserve the old format.
            // ---------------------------------------------------------------
            b.Property<string>("__id")
             .ToJsonProperty("id")
             .HasValueGenerator<LegacyCosmosIdGenerator>();

            // ---------------------------------------------------------------
            // BREAKING CHANGE 3 — HasIndex is not supported on Cosmos
            // EF Core 8 silently ignored this; EF Core 9 throws at model
            // build time. Cosmos indexing is managed through indexing policy
            // on the container, not via EF model configuration.
            // Fix: removed the HasIndex call.
            // ---------------------------------------------------------------
            // REMOVED: b.HasIndex(p => p.Sku);
        });
    }
}

/// <summary>
/// Generates Cosmos document ids in the EF Core 8 format ("Product|{PK}")
/// so new documents stay compatible with the 500K existing ones.
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    public override string Next(EntityEntry entry)
        => $"Product|{entry.Property("Id").CurrentValue}";
}

