using System.Linq;
using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    // ---------------------------------------------------------------
    // BREAKING CHANGE 4 — Synchronous I/O no longer supported
    // EF Core 9 Cosmos provider throws InvalidOperationException on
    // sync calls (ToList, First, Single, etc.).
    // Fix: use the async equivalents everywhere.
    // ---------------------------------------------------------------

    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — works unchanged because we preserved the
        // "Discriminator" property name (see Breaking Change 1).
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        var products = await ctx.Products
            .Where(p => p.Sku == "ABC")
            .ToListAsync();
    }
}

